from zeep import Client
import sys

# Replace with the actual WSDL URL provided by the third-party insurance service
wsdl_url = "http://insurance-service.com/services?wsdl"

client = Client(wsdl=wsdl_url)

def lookup_policy(policy_number, customer_name):
    policy_lookup_response = client.service.PolicyLookup({
        "PolicyNumber": policy_number,
        "CustomerName": customer_name
    })
    return policy_lookup_response

if __name__ == "__main__":
    policy_number = sys.argv[1] if len(sys.argv) > 1 else input("Enter Policy Number: ")
    customer_name = sys.argv[2] if len(sys.argv) > 2 else input("Enter Customer Name: ")

    response = lookup_policy(policy_number, customer_name)
    print(f"Policy Lookup Response:\n{response}")